function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
  const rounded = Math.ceil(total);
  const fractional = total % 1;

  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;

  if (shouldApplyExtraRound) {
    return rounded + 1;
  }

  return rounded;
}

